* **Version**: v12.18.1
* **Platform**: Windows 10
* **Subsystem**: `fs`

### What steps will reproduce the bug?

I found that calling `fs.createWriteStream` with certain filenames will cause nodejs to immediately crash.  This seems to only happen on Windows (I've only tried Windows 10) but not on Mac/Linux.

```
const fs = require('fs');

async function run() {
    try {
        const stream = fs.createWriteStream('search?q=pictures&rlz=1C1SQJL_enUA901UA901');
        stream.close();

        await new Promise((resolve, reject) => {
            setTimeout(() => {
                console.log('timeout resolved');
                resolve();
            }, 10000);
        });

        process.exit(0);
    } catch (err) {
        console.log('Recevied error',err);
        process.exit(1);
    }
}

run();
```

Running on Windows results in the following which kills nodejs immediately.
```
>node test.js
events.js:292
      throw er; // Unhandled 'error' event
      ^

Error: ENOENT: no such file or directory, open 'C:\Users\adam\Development\search?q=pictures&rlz=1C1SQJL_enUA901UA901'
Emitted 'error' event on WriteStream instance at:
[90m    at internal/fs/streams.js:376:12[39m
[90m    at FSReqCallback.oncomplete (fs.js:155:23)[39m {
  errno: [33m-4058[39m,
  code: [32m'ENOENT'[39m,
  syscall: [32m'open'[39m,
  path: [32m'C:\\Users\\adam\\Development\\search?q=pictures&rlz=1C1SQJL_enUA901UA901'[39m
}
```

If I add an event handler for the stream error, then it doesn't crash:
```
        stream.on('error', (err) => {
            stream.close();
        });
```

So yes, catching the stream error does "resolve" this issue, but I'm reporting this because nodejs's behavior is different on Windows than on Linux/mac and I would expect them to behave the same.

text:
Creating writeStream on windows with certain filenames causes nodejs crash

* ** **: v12.18.1
* ** **: Windows 10
* ** **: `fs`

### 

I found that calling `fs.createWriteStream` with certain filenames will cause nodejs to immediately crash. This seems to only happen on Windows (I've only tried Windows 10) but not on Mac/Linux.

```
const fs = require('fs');

async function run() {
 try {
 const stream = fs.createWriteStream('search?q=pictures&rlz=1C1SQJL_enUA901UA901');
 stream.close();

 await new Promise((resolve, reject) => {
 setTimeout(() => {
 console.log('timeout resolved');
 resolve();
 }, 10000);
 });

 process.exit(0);
 } catch (err) {
 console.log('Recevied error',err);
 process.exit(1);
 }
}

run();
```

Running on Windows results in the following which kills nodejs immediately.
```
>node test.js
events.js:292
 throw er; // Unhandled 'error' event
 ^

Error: ENOENT: no such file or directory, open 'C:\Users\adam\Development\search?q=pictures&rlz=1C1SQJL_enUA901UA901'
Emitted 'error' event on WriteStream instance at:
[90m at internal/fs/streams.js:376:12[39m
[90m at FSReqCallback.oncomplete (fs.js:155:23)[39m {
 errno: [33m-4058[39m,
 code: [32m'ENOENT'[39m,
 syscall: [32m'open'[39m,
 path: [32m'C:\\Users\\adam\\Development\\search?q=pictures&rlz=1C1SQJL_enUA901UA901'[39m
}
```

If I add an event handler for the stream error, then it doesn't crash:
```
 stream.on('error', (err) => {
 stream.close();
 });
```

So yes, catching the stream error does "resolve" this issue, but I'm reporting this because nodejs's behavior is different on Windows than on Linux/mac and I would expect them to behave the same.

