* **node: v8.16.0**:
* ** : Ubuntu 18.04.1 LTS 2019, x64**
* **Module: async_hooks**:

### The destroy event is never raised when resolving a Promise. Possible memory leak ?

```js
const fs = require('fs');
const ah = require('async_hooks');

let hook = ah.createHook({
 init,
 destroy
});
hook.enable();
hook = null;

function init(asyncId) {
 fs.writeSync(1, `init ${asyncId}\n`);
}

function destroy(asyncId) {
 fs.writeSync(1, `destroy ${asyncId}\n`);
}

function run(cb) {
 return Promise.resolve(1)
 .then(() => {
 return cb();
 });
}

run(cb);

function cb() {
 setTimeout(onTimeout, 300);
}


function onTimeout() {
 console.log('onTimeout');
}
```
Output:
```
init 5
init 6
init 7
init 8
onTimeout
init 9
destroy 7
destroy 9
destroy 8
```

Expected output:
```
init 5
init 6
init 7
init 8
onTimeout
init 9
destroy 7
destroy 9
destroy 8
destroy 6
destroy 5
```

